using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train the model at startup so the prediction pool has a model file to load.
builder.Services.AddSingleton<ModelTrainingService>();
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train before first request if model doesn't exist or on explicit retrain.
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
var report = trainer.TrainAndSave(dataPath, modelPath);
app.Logger.LogInformation("Startup training complete.\n{Report}", report);

app.MapControllers();
app.Run();

